public class BinarySearchVariants {

    public int firstOccurrence(int[] arr, int target) {
        int low = 0, high = arr.length - 1, result = -1;
        while (low <= high) {
            int mid = low + (high - low) / 2;
            if (arr[mid] == target) {
                result = mid;
                // TODO: continue searching left: high = mid - 1
            } else if (arr[mid] < target) {
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        return result;
    }

    public int lastOccurrence(int[] arr, int target) {
        int low = 0, high = arr.length - 1, result = -1;
        while (low <= high) {
            int mid = low + (high - low) / 2;
            if (arr[mid] == target) {
                result = mid;
                // TODO: continue searching right: low = mid + 1
            } else if (arr[mid] < target) {
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        return result;
    }

    public int countOccurrences(int[] arr, int target) {
        int first = firstOccurrence(arr, target);
        if (first == -1) return 0;
        return lastOccurrence(arr, target) - first + 1;
    }

    public static void main(String[] args) {
        BinarySearchVariants bsv = new BinarySearchVariants();
        int[] arr = {1, 2, 2, 2, 3, 4, 4, 5};
        System.out.println("First 2: " + bsv.firstOccurrence(arr, 2));
        System.out.println("Last  2: " + bsv.lastOccurrence(arr, 2));
        System.out.println("Count 2: " + bsv.countOccurrences(arr, 2));
        System.out.println("Count 4: " + bsv.countOccurrences(arr, 4));
        System.out.println("Count 6: " + bsv.countOccurrences(arr, 6));
    }
}

